"C:\\Program Files\\PowerShell\\7\\pwsh.exe" -Command "@'
const fs=require('fs');
const businesses=JSON.parse(fs.readFileSync('docs/businesses.json','utf8'));
const geo=JSON.parse(fs.readFileSync('docs/businesses.geojson','utf8'));
const count=(fn)=>businesses.filter(fn).length;
const groups=(key)=>Object.entries(businesses.reduce((a,b)=>{const k=b[key]||'(blank)'; a[k]=(a[k]||0)+1; return a;},{})).sort((a,b)=>b[1]-a[1]);
console.log(JSON.stringify({
 total: businesses.length,
 geoFeatures: geo.features.length,
 coords: count(b=>parseFloat(b.latitude)&&parseFloat(b.longitude)),
 cid: count(b=>b.cid||b.google_maps_cid||b.maps_cid),
 phone: count(b=>b.normalized_phone||b.phone),
 instagram: count(b=>b.instagram_handle),
 facebook: count(b=>b.facebook_url||b.facebook),
 whatsapp: count(b=>b.whatsapp),
 booking: count(b=>b.booking_url),
 tripadvisor: count(b=>b.tripadvisor_url),
 categories: groups('category'),
 areas: groups('area').slice(0,10),
 sampleKeys: Object.keys(businesses[0])
}, null, 2));
